    @Scheduled(cron = "0 30 15 * * MON-FRI")
    public void runDailySettlement() {
        String key = "lock:settlement:" + java.time.LocalDate.now();
        boolean ran = lock.runOnce(key, Duration.ofMinutes(15), () -> {
            log.info("Running settlement...");
            // ... settlement logic ...
            log.info("Settlement done.");
        });
        if (!ran) log.info("Settlement skipped — already running elsewhere");
    }
}
